import React from 'react';
import { Link, Outlet, useLocation } from 'react-router-dom';
import { ReduxToastContainer, useResponsive } from '@linm-soft/common-components';
import '@linm-soft/common-components/styles/variables.css';
import { isStandalone, showDevNav } from '../../../dev/isStandalone';
import { isVoucherFormPath } from '../../../utils/isVoucherFormPath';
import styles from './AppLayout.module.css';

const getPageTitle = (pathname: string): string => {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/mh')) return 'Mua Hàng';
  if (pathname.startsWith('/kho')) return 'Kho / WMS';
  return 'ERP Cung Ứng';
};

export const AppLayout: React.FC = () => {
  const location = useLocation();
  const { isMobile } = useResponsive();
  const title = getPageTitle(location.pathname);
  const voucherFormShell = isVoucherFormPath(location.pathname);

  return (
    <div
      className={isStandalone ? `${styles.main} ${styles.mainStandalone}` : styles.main}
      data-modal-root
    >
      <header className={styles.topbar}>
        <div className={styles.topbarLeft}>
          {isMobile && (
            <button
              type="button"
              className={styles.menuButton}
              onClick={() => window.dispatchEvent(new CustomEvent('linm:nav:toggle-mobile'))}
              aria-label="Mở menu"
            >
              <i className="fas fa-bars" />
            </button>
          )}
          <h1 className={styles.title}>{title}</h1>
        </div>
        {showDevNav && !location.pathname.startsWith('/dev') && (
          <Link to="/dev" className={styles.devLink} title="Dev Navigation">
            <i className="fas fa-wrench" aria-hidden />
          </Link>
        )}
      </header>
      <div
        className={[
          styles.content,
          voucherFormShell ? styles.contentVoucherShell : '',
        ].filter(Boolean).join(' ')}
      >
        <Outlet />
      </div>
      {isStandalone && <ReduxToastContainer />}
    </div>
  );
};

export default AppLayout;
